# Generated by openai (o3)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any

    options {
        skipDefaultCheckout(true)
        timestamps()
    }

    parameters {
        text(
            name: 'ARTIFACT_URLS',
            defaultValue: 'https://s3.amazonaws.com/mybucket/app.war',
            description: 'One URL per line or comma-separated list of artifacts to deploy'
        )
        choice(
            name: 'TARGET_CLUSTER',
            choices: ['prod-west', 'prod-east'],
            description: 'Production cluster to deploy to'
        )
    }

    environment {
        DOWNLOAD_DIR = 'downloaded_artifacts'
        DEPLOY_USER  = 'deployuser'
        PROD_WEST    = 'app01-west.company.com app02-west.company.com'
        PROD_EAST    = 'app01-east.company.com app02-east.company.com'
    }

    stages {

        stage('Prepare Workspace') {
            steps {
                sh "rm -rf ${env.DOWNLOAD_DIR} && mkdir -p ${env.DOWNLOAD_DIR}"
            }
        }

        stage('Download Artifacts') {
            steps {
                script {
                    def urls = params.ARTIFACT_URLS
                                 .split(/[\n,]+/)
                                 .collect { it.trim() }
                                 .findAll { it }

                    if (urls.isEmpty()) {
                        error 'No artifact URLs provided'
                    }

                    urls.each { url ->
                        def filename = url.tokenize('/')[-1]
                        sh """
                            echo "Downloading ${url}"
                            curl -sSL --fail -o '${env.DOWNLOAD_DIR}/${filename}' '${url}'
                        """
                    }
                }
            }
        }

        stage('Deploy to Production') {
            steps {
                script {
                    def hosts = (params.TARGET_CLUSTER == 'prod-west'
                                 ? env.PROD_WEST
                                 : env.PROD_EAST).split()

                    withCredentials([
                        sshUserPrivateKey(
                            credentialsId: 'prod-deploy-key',
                            keyFileVariable: 'SSH_KEY'
                        )
                    ]) {
                        hosts.each { host ->
                            sh """
                                echo "Deploying to ${host}"
                                scp -i \$SSH_KEY -o StrictHostKeyChecking=no ${env.DOWNLOAD_DIR}/* ${env.DEPLOY_USER}@${host}:/opt/apps/
                                ssh -i \$SSH_KEY -o StrictHostKeyChecking=no ${env.DEPLOY_USER}@${host} 'sudo systemctl restart myapp'
                            """
                        }
                    }
                }
            }
        }
    }

    post {
        failure {
            mail to: 'ops@company.com',
                 subject: "Deployment failed: ${env.JOB_NAME} #${env.BUILD_NUMBER}",
                 body: "Check Jenkins for details: ${env.BUILD_URL}"
        }
    }
}